    struct Stack* node = Node(value, root -> next);
    root -> next = node;
}

// pop from the stack.
void* pop(struct Stack* root) {
    void* value = root -> next -> value;
    struct Stack* delete_node = root -> next;
    root -> next = root -> next -> next;
    free(delete_node);
    return value;
}

