    fun dfs(nums: IntArray, target: Int, idx: Int, list: MutableList<Int>, res: MutableList<List<Int>>) {

        if (target == 0) {
            res.add(ArrayList(list))
            return
        }

        if (idx >= nums.size || target < 0)
            // [Reader note] Return
            // The final return exposes the result after the traversal and state updates have settled.
            return

        // [Reader note] Main pass
        // This is the main sweep where the implementation earns its efficiency instead of restarting work from scratch.
        for (i in idx..nums.size-1) {
            list.add(nums[i])
            dfs(nums, target - nums[i], i, list, res)
            list.removeAt(list.size-1)
        }
    }
}
